import pytest

AC_UID = "ac4-20260521-090100-all-tee-sites-hook-resolvable-both-files"
AC_TYPE = "data"


def test_AC4():
    """
    GIVEN: commands/codex.md AND /root/.agents/skills/codex/SKILL.md after the change
    WHEN:  all physical tee invocations in both files are inspected (regardless of branch count)
    THEN:  zero occurrences of 'tee "$CODEX_OUT"' or 'tee "${CODEX_OUT}"' exist in EITHER file; AND every physical tee target in both files is one of: '$CLAUDE_PROJECT_DIR/docs/codex/$CODEX_OUT_TASK_ID/$CODEX_OUT_ROLE.txt' (canonical branch), or '/var/tmp/codex-outputs/codex-output-$$-$(date +%s).txt' (fallback literal); AND command-substitution tee forms 'tee "$(...)' or 'tee $(...)' are absent from both files
    """
    # TODO(dev): replace the line below with the real test body. While the
    # TEST_INCOMPLETE sentinel is present the test will hard-fail, marking
    # the AC as unimplemented for QA Phase 5.
    import os, re
    codex_file = os.path.join(os.path.dirname(__file__), "..", "..", "..", "commands", "codex.md")
    skill_file = "/root/.agents/skills/codex/SKILL.md"

    for filepath in [codex_file, skill_file]:
        assert os.path.exists(filepath), f"File not found: {filepath}"
        with open(filepath) as f:
            content = f.read()

        # Negative check: no opaque $CODEX_OUT or ${CODEX_OUT} as tee target
        opaque_tee_matches = re.findall(r'tee\s+"?\$\{?CODEX_OUT\}?"?', content)
        assert len(opaque_tee_matches) == 0, (
            f"{filepath}: found opaque tee target(s): {opaque_tee_matches}"
        )

        # Negative check: no command-substitution tee forms
        cmd_sub_matches = re.findall(r'tee\s+"\$\(', content)
        assert len(cmd_sub_matches) == 0, (
            f"{filepath}: found command-substitution tee form(s): {cmd_sub_matches}"
        )

        # Positive check: all actual tee targets in code blocks must be hook-resolvable
        # Extract lines with tee that are actual bash commands (not documentation)
        tee_lines = [line.strip() for line in content.splitlines() if re.search(r'\|\s*tee\s+', line)]
        for line in tee_lines:
            is_canonical = 'CLAUDE_PROJECT_DIR/docs/codex' in line
            is_fallback = '/var/tmp/codex-outputs/codex-output' in line
            assert is_canonical or is_fallback, (
                f"{filepath}: tee target not hook-resolvable: {line}"
            )
